package gui;
import manager.VendingMachineManager; import model.Drink;
import javax.swing.*; import java.awt.*; import java.util.Map;
public class CustomerPanel extends JPanel{ private final VendingMachineManager manager; private final Runnable refreshFrame; private final JPanel drinks=new JPanel(new GridLayout(0,2,8,8)); private final JLabel money=new JLabel(); private boolean adminActive;
 public CustomerPanel(VendingMachineManager m,Runnable r){manager=m;refreshFrame=r; setLayout(new BorderLayout(10,10)); add(drinks,BorderLayout.CENTER); JPanel side=new JPanel(new GridLayout(0,1,5,5)); int[] units={10,50,100,500,1000}; for(int u:units){ JButton b=new JButton(u+"원 투입"); b.addActionListener(e->safe(()->manager.insertMoney(u))); side.add(b);} JButton refund=new JButton("환불"); refund.addActionListener(e->safe(()->{Map<Integer,Integer> c=manager.refund(); JOptionPane.showMessageDialog(this,"반환: "+c);})); side.add(money); side.add(refund); add(side,BorderLayout.EAST); refresh(false); }
 public void refresh(boolean adminActive){ this.adminActive=adminActive; money.setText("투입 금액: "+manager.getInsertedTotal()+"원"); drinks.removeAll(); for(Drink d:manager.getDrinks()){ JButton b=new JButton(d.isSoldOut()?d.getName()+" 품절":d.getName()+" "+d.getPrice()+"원 / 재고 "+d.getStock()); b.setEnabled(!adminActive && !d.isSoldOut() && manager.getInsertedTotal()>=d.getPrice()); b.addActionListener(e->safe(()->{Map<Integer,Integer> c=manager.buy(d.getId()); JOptionPane.showMessageDialog(this,d.getName()+" 배출, 거스름돈 "+c);})); drinks.add(b);} revalidate(); repaint(); }
 private void safe(Throwing t){ if(adminActive){JOptionPane.showMessageDialog(this,"관리자 화면 사용 중에는 판매 기능이 정지됩니다.");return;} try{t.run();}catch(Exception ex){JOptionPane.showMessageDialog(this,ex.getMessage());} refreshFrame.run(); } interface Throwing{void run() throws Exception;} }
